#include <cuda_runtime.h>
#include <cuda.h>
#include <device_launch_parameters.h>
#include <stdio.h>
#include <math.h>
#include <sys/time.h>
#include <limits.h>

#define PI 3.1415926535897932

// Define constants
__constant__ long M = INT_MAX;
__constant__ int A = 1103515245;
__constant__ int C = 12345;

// Function to get time
__host__ long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

// Function to calculate elapsed time
__host__ float elapsed_time(long long start_time, long long end_time) {
    return (float) (end_time - start_time) / (1000 * 1000);
}

// Function to round a double to an integer
__device__ double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return newValue;
    else
        return newValue + 1;
}

// Kernel to set values in a 3D array
__global__ void setIfKernel(int testValue, int newValue, int* array3D, int dimX, int dimY, int dimZ) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;
    int z = blockIdx.z * blockDim.z + threadIdx.z;

    if (x < dimX && y < dimY && z < dimZ) {
        if (array3D[x * dimY * dimZ + y * dimZ + z] == testValue)
            array3D[x * dimY * dimZ + y * dimZ + z] = newValue;
    }
}

// Kernel to generate a uniformly distributed random number
__device__ double randu(int* seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

// Kernel to generate a normally distributed random number
__device__ double randn(int* seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

// Kernel to add noise to a 3D array
__global__ void addNoiseKernel(int* array3D, int dimX, int dimY, int dimZ, int* seed) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;
    int z = blockIdx.z * blockDim.z + threadIdx.z;

    if (x < dimX && y < dimY && z < dimZ) {
        array3D[x * dimY * dimZ + y * dimZ + z] = array3D[x * dimY * dimZ + y * dimZ + z] + (int)(5 * randn(seed, 0));
    }
}

// Kernel to dilate a matrix
__global__ void dilateMatrixKernel(int* matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;

    if (x < dimX && y < dimY) {
        double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
        if (distance < error)
            matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
    }
}

// Kernel to dilate a matrix using a disk
__global__ void imdilateDiskKernel(int* matrix, int dimX, int dimY, int dimZ, int error, int* newMatrix) {
    int z = blockIdx.x * blockDim.x + threadIdx.x;
    int x = blockIdx.y * blockDim.y + threadIdx.y;
    int y = blockIdx.z * blockDim.z + threadIdx.z;

    if (z < dimZ && x < dimX && y < dimY) {
        if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
            dilateMatrixKernel<<<dim3(16, 16, 1), dim3(16, 16, 1)>>>(newMatrix, x, y, z, dimX, dimY, dimZ, error);
        }
    }
}

// Kernel to calculate the likelihood sum
__global__ void calcLikelihoodSumKernel(int* I, int* ind, int numOnes, double* likelihoodSum) {
    int y = blockIdx.x * blockDim.x + threadIdx.x;

    if (y < numOnes) {
        likelihoodSum[0] += (pow((I[ind[y]] - 100), 2) - pow((I[ind[y]] - 228), 2)) / 50.0;
    }
}

// Kernel to find the index in a CDF
__global__ void findIndexKernel(double* CDF, int lengthCDF, double value, int* index) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;

    if (x < lengthCDF) {
        if (CDF[x] >= value) {
            *index = x;
        }
    }
}

// Kernel to calculate the particle filter
__global__ void particleFilterKernel(int* I, int IszX, int IszY, int Nfr, int* seed, int Nparticles) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;

    if (x < Nparticles) {
        // Apply motion model
        double arrayX = roundDouble(IszY / 2.0);
        double arrayY = roundDouble(IszX / 2.0);
        arrayX += 1 + 5 * randn(seed, x);
        arrayY += -2 + 2 * randn(seed, x);

        // Calculate likelihood
        int indX, indY;
        double likelihood = 0;
        for (int y = 0; y < 25; y++) {
            indX = roundDouble(arrayX) + y % 5 - 2;
            indY = roundDouble(arrayY) + y / 5 - 2;
            int ind = indX * IszY * Nfr + indY * Nfr + 1;
            if (ind >= IszX * IszY * Nfr)
                ind = 0;
            likelihood += (pow((I[ind] - 100), 2) - pow((I[ind] - 228), 2)) / 50.0;
        }
        likelihood /= 25;

        // Update and normalize weights
        double weights = likelihood;
        weights = weights * exp(likelihood);
    }
}

int main(int argc, char* argv[]) {
    // Check number of arguments
    if (argc != 9) {
        printf("Usage: %s -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>\n", argv[0]);
        return 0;
    }

    // Check args deliminators
    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("Usage: %s -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>\n", argv[0]);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    // Converting a string to a integer
    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect\n");
        return 0;
    }

    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    // Converting a string to a integer
    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect\n");
        return 0;
    }

    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    // Converting a string to a integer
    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect\n");
        return 0;
    }

    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    // Converting a string to a integer
    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect\n");
        return 0;
    }

    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    // Establish seed
    int* seed = (int*)malloc(sizeof(int) * Nparticles);
    int i;
    for (i = 0; i < Nparticles; i++)
        seed[i] = time(0) * i;

    // Malloc matrix
    int* I = (int*)malloc(sizeof(int) * IszX * IszY * Nfr);

    long long start = get_time();

    // Call video sequence
    videoSequence(I, IszX, IszY, Nfr, seed);

    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

    // Call particle filter
    particleFilterKernel<<<1, 1>>>(I, IszX, IszY, Nfr, seed, Nparticles);

    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));

    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);

    return 0;
}

void videoSequence(int* I, int IszX, int IszY, int Nfr, int* seed) {
    int max_size = IszX * IszY * Nfr;
    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (int k = 1; k < Nfr; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    int* newMatrix = (int*)malloc(sizeof(int) * IszX * IszY * Nfr);
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);

    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }

    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);

    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

void setIf(int testValue, int newValue, int* array3D, int* dimX, int* dimY, int* dimZ) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                if (array3D[x * (*dimY) * (*dimZ) + y * (*dimZ) + z] == testValue)
                    array3D[x * (*dimY) * (*dimZ) + y * (*dimZ) + z] = newValue;
            }
        }
    }
}

void addNoise(int* array3D, int* dimX, int* dimY, int* dimZ, int* seed) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                array3D[x * (*dimY) * (*dimZ) + y * (*dimZ) + z] = array3D[x * (*dimY) * (*dimZ) + y * (*dimZ) + z] + (int)(5 * randn(seed, 0));
            }
        }
    }
}

void imdilate_disk(int* matrix, int dimX, int dimY, int dimZ, int error, int* newMatrix) {
    int x, y, z;
    for (z = 0; z < dimZ; z++) {
        for (x = 0; x < dimX; x++) {
            for (y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void dilate_matrix(int* matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0)
        startX++;
    int startY = posY - error;
    while (startY < 0)
        startY++;
    int endX = posX + error;
    while (endX > dimX)
        endX--;
    int endY = posY + error;
    while (endY > dimY)
        endY--;

    int x, y;
    for (x = startX; x < endX; x++) {
        for (y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

